import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

function CreatePostPage() {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [image, setImage] = useState(null);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    
    const fd = new FormData();
    fd.append('title', title);
    fd.append('body', body);
    if (image) fd.append('image', image);
    
    try {
      const { data } = await API.post('/posts', fd, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      navigate(`/posts/${data._id}`); // Direct to the new post
    } catch (err) { 
      alert(err.response?.data?.message || 'Error publishing post');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className='create-post-page'>
      <form onSubmit={handleSubmit}>
        <input type='text' placeholder='Title' onChange={e => setTitle(e.target.value)} required />
        <textarea placeholder='Content' onChange={e => setBody(e.target.value)} required />
        <input type='file' accept='image/*' onChange={e => setImage(e.target.files[0])} />
        <button type='submit' disabled={loading}>{loading ? 'Saving...' : 'Publish'}</button>
      </form>
    </div>
  );
}
export default CreatePostPage;
